mapper.select:
select i.*, g.goods_name, g.goods_code, w.warehouse_name, o.owner_name from inventory i left join goods g on i.goods_id=g.goods_id left join warehouse w on i.warehouse_id=w.warehouse_id left join owner o on i.owner_id=o.owner_id where 1=1
and g.goods_name like concat('%',#{goodsName},'%')
and o.owner_name like concat('%',#{ownerName},'%')
and i.warehouse_id=#{warehouseId}
and i.goods_id=#{goodsId}
and i.owner_id=#{ownerId}
order by i.inventory_id desc

mapper.update:
update inventory set quantity=quantity-#{quantity}, update_time=now()
where goods_id=#{goodsId} and warehouse_id=#{warehouseId} and owner_id=#{ownerId}
and quantity >= #{quantity}
